import string
def gen(rng, size):
    letters = 'abcde'
    vocab = [''.join(rng.choice(letters) for _ in range(rng.randint(1, 6))) for _ in range(20)]
    ops = ['Trie']
    args = [[]]
    for _ in range(max(1, size)):
        r = rng.random()
        w = rng.choice(vocab)
        if r < 0.4:
            ops.append('insert'); args.append([w])
        elif r < 0.7:
            ops.append('search'); args.append([w])
        else:
            ops.append('startsWith'); args.append([w[:rng.randint(1, len(w))]])
    return [ops, args]

