class Trie {
    constructor() {
        this.root = {};
    }
    insert(word) {
        let node = this.root;
        for (const c of word) {
            if (!(c in node)) node[c] = {};
            node = node[c];
        }
        node['$'] = true;
    }
    search(word) {
        let node = this.root;
        for (const c of word) {
            if (!(c in node)) return false;
            node = node[c];
        }
        return node['$'] === true;
    }
    startsWith(prefix) {
        let node = this.root;
        for (const c of prefix) {
            if (!(c in node)) return false;
            node = node[c];
        }
        return true;
    }
}
